#include<iostream>#include<vector> using namespace std; int solve(vector<int>& arr , int x){    int max_Dist = arr[0];     for(int i = 1 ; i < arr.size() ; i++){        max_Dist = max(max_Dist , arr[i] - arr[i-1]);    }    max_Dist = max(max_Dist , 2 * (x - arr[arr.size() - 1]));     return max_Dist;} int main(){    int t;    cin >> t;     while(t--){        int n , x;         cin >> n >> x;         vector<int>arr(n);         for(int i = 0 ; i < n ; i++) cin >> arr[i];         int res = solve(arr , x);         cout << res << "\n";    }    return 0;}